+  const recursiveSchema: RecursiveSchema<TWrapped> = {
+    kind: 'schema',
+    type: 'recursive',
+    reference: recursive,
+    expects: 'unknown',
+    async: false,
+    get wrapped() {
+      return wrapped;
+    },
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset, config) {
+      return wrapped['~run'](dataset, config);
+    },
+  };
