+/**
+ * Resolves recursive placeholders in a schema.
+ *
+ * @param schema The schema to resolve.
+ * @param recursiveSchema The recursive schema.
+ *
+ * @returns The resolved schema.
+ *
+ * @internal
+ */
+function _resolveRecur<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
+  schema: TSchema,
+  recursiveSchema: BaseSchema<unknown, unknown, BaseIssue<unknown>>
+): TSchema {
+  if (schema === Recur) {
+    return recursiveSchema as TSchema;
+  }
+
+  const clone = Object.create(
+    Object.getPrototypeOf(schema),
+    Object.getOwnPropertyDescriptors(schema)
+  ) as TSchema;
+  for (const key of ['item', 'key', 'value', 'rest'] as const) {
+    if (key in clone) {
+      _setProperty(clone, key, _resolveRecur(clone[key] as TSchema, recursiveSchema));
+    }
+  }
+  if ('entries' in clone) {
+    _setProperty(
+      clone,
+      'entries',
+      Object.fromEntries(
+        Object.entries(clone.entries as Record<string, TSchema>).map(([key, value]) => [
+          key,
+          _resolveRecur(value, recursiveSchema),
+        ])
+      )
+    );
+  }
+  for (const key of ['options', 'pipe'] as const) {
+    if (key in clone) {
+      _setProperty(
+        clone,
+        key,
+        (clone[key] as readonly TSchema[]).map((item) =>
+          _resolveRecur(item, recursiveSchema)
+        )
+      );
+    }
+  }
+  return clone;
+}
+
+/**
+ * Sets a schema property.
+ *
+ * @param schema The schema.
+ * @param key The property key.
+ * @param value The property value.
+ *
+ * @internal
+ */
+function _setProperty<TSchema extends object, TKey extends PropertyKey>(
+  schema: TSchema,
+  key: TKey,
+  value: unknown
+): void {
+  Object.defineProperty(schema, key, {
+    configurable: true,
+    enumerable: true,
+    value,
+    writable: false,
+  });
+}
